INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00410', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X5年1月1日以一股$50購買丁公司流通在外股數80,000股的16,000股，不考慮交易成 本，共投入$800,000。丁公司X5年度發放現金股利一股$4，當年度淨利為$500,000，年底股價一 股為$53，試問甲公司若將丁公司股票列為「採用權益法之投資」相對於列為「透過其他綜合損益 按公允價值衡量」，X5年12月31日資產的帳面價值會如何？', '["少$12,000", "少$28,000", "都一樣", "多$372,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00411', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司 X4 年初購入芒果樹苗開始種植芒果樹，至 X6 年初達成熟階段而開始收成芒果。累計所 有相關支出並考慮耐用年限及殘值，每年折舊費用為$40,000，X6 年收成的芒果依公開市場報價 為$230,000，採收芒果的支出為$80,000，送至市場的運費為$6,000，出售成本為$4,000。試問X6 年芒果收成的當期原始認列農產品利益為多少？', '["$100,000", "$140,000", "$220,000", "$226,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00412', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列有關公司資產「商譽」的敘述，何者正確？', '["商譽代表公司具有自行發展出來的經營優勢", "商譽是公司的無形資產，每年必須攤銷", "商譽於報導期間內若有減損跡象，應立即進行減損測試且每年定期進行減損測試", "商譽減損損失可迴轉，但不得超過未認列減損損失情況下減除應提攤銷後之帳面值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00413', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司於X4年1月初購買一棟商辦大樓予以出租以獲取租金，支付成本包括購價$3,000,000，稅 捐成本$200,000，外牆安全加強$600,000，預估大樓耐用年限40年，外牆安全加強每10年須進行 一次。公司對於折舊提列皆採直線法，對此商辦大樓採公允價值模式，X4年12月31日該商辦大 樓公允價值為$3,700,000，試問乙公司12月31日會認列：', '["公允價值調整損失$100,000", "公允價值調整損失$5,000", "公允價值調整利益$40,000", "公允價值調整利益$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00414', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司X4年7月1日購入一商業旅館（不含土地）總價為$5,000,000，預估商旅耐用年限為40 年，採直線法提折舊，無殘值。此商旅每四年須進行房間重新裝潢，成本為$1,000,000。X8 年 1 月1日公司決定提前進行裝潢工作，相關成本為$1,200,000，並預期下次裝潢將在X11年初進行。 試問X8年度丙公司商旅所產生之處分損益及折舊費用對當期損益之影響為何？', '["減少$125,000", "減少$400,000", "減少$525,000", "減少$625,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00415', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司與客戶簽訂銷貨合約，並給予客戶30日內可無條件退貨，公司須全額退費。合約的銷貨價 格每件$30，共200件，商品成本每件$20。若公司預估退貨為30件，試問公司應認列之交易分錄 下列何者正確？', '["借：應收帳款$5,100", "借：銷貨成本$4,000", "貸：退款負債$900", "貸：存貨$3,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00416', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司存貨採定期盤存制，X4年期初存貨為$3,200，當期進貨運費$800，進貨退回$1,000，當期 進貨付款皆在折扣期內取得2%，折扣共有$300，若期末存貨盤點為$2,100，試問X4年銷貨成本 為多少？', '["$15,600", "$15,800", "$16,000", "$16,600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00417', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X4年比較性資產負債表顯示機器設備淨增加$20,000，相關累計折舊淨增加$15,000，當年 度甲公司僅購買一新機器設備成本$35,000，並出售一機器設備產生處分損失$1,800，當年機器設備 提列之折舊費用為$25,000。試問在當年現金流量表上投資活動出售機器設備之現金流入為多少？', '["$3,200", "$5,000", "$6,800", "$8,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00418', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '乙公司只發行普通股，若X2年權益報酬率為12%，淨利率為8%，負債比率為60%，試問當年度 的資產週轉率為多少？', '["0.4", "0.6", "1.2", "2.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00419', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司X7年平均應收帳款為$60,000，平均存貨為$50,000，若存貨平均銷售天數為25天，毛利 率為20%，X7年丙公司的應收帳款平均收款天數為幾天？（一年皆以360天計）', '["15天", "24天", "30天", "36天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:56+00:00", "source_pdf_sha1": "5e8d2b41a0ff", "answer_pdf_sha1": "fc2ea2237657", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
